public static function delete(string $dir, bool $isIncludeSelf = false):bool
    {
        if (!is_dir($dir)) {
            return false;
        }
        $handle = opendir($dir);
        while ($file = readdir($handle)) {
            if ($file != '.' && $file != '..') {
                $realPath = realpath($dir . '/' . $file);
                if (is_dir($realPath)) {
                    static::delete($realPath, true);
                } else {
                    unlink($realPath);
                }
            }
        }
        closedir($handle);
        if ($isIncludeSelf) {
            return rmdir($dir);
        }
        return true;
    }

