        $strHead = "";
        $strBody = "";

        foreach ($head as $thRow) {
            $strHead .= self::renderTableHeaderRow($thRow);
        }
        if ($strHead != "") {
            $strHead = self::thead($strHead);
        }

        foreach ($body as $tr) {
            $strBody .= self::renderTableRow($tr);
        }
        if ($strBody != "") {
