public function dump(Criteria $criteria)
    {
        $mode = strtoupper($criteria->getMode());

        $parts = array();
        foreach ($criteria as $criterium) {
            if ($criterium instanceof Criteria) {
                $parts[] = $this->dump($criterium, 1);
            } elseif ($criterium instanceof Criterium) {
                $type = $criterium->getType();
                $value = $criterium->getValue();
                if ($value instanceof \DateTime) {
                    $parts[] = $type.' = "'.$value->format('Y-m-d H:i:s').'"';
                } else {
                    $parts[] = $type.' = "'.$value.'"';
                }
            }
        }

        return '('.implode(' '.$mode.' ', $parts).')';
    }

public function getResourceConfigurationFromRequest($route)
    {
        // get just the base url without query string
        $route = parse_url($route, PHP_URL_PATH);

        // remove any slashes from begining/end
        $route = trim($route, " /");

        // get the base resource excluding any single identifiers
        $parts = explode('/', $route);
        $resource = is_numeric(end($parts)) ? prev($parts):end($parts);

        return $this->resourceConfigurationFor($resource);
    }

