public static function path($src, $tail = '', $w = 0, $h = 0) {
        if ($src == '') {
            return '';
        }
        if ($tail == '') {
            return $src;
        }
        $temp = pathinfo($src);
        $name = $temp['filename'];
        $path = $temp['dirname'];
        $exte = $temp['extension'];
        $dest = $path . '/' . $name . '_' . $tail . '.' . $exte;
        if (!file_exists(WEB_ROOT . $dest)) {
            $dest = self::image_widthin($src, $dest, $w, $h);
        }
        return $dest;
    }

