protected function containsIn($value, $strict, $in)
    {
        $found = FALSE;
        $keys = array_keys($in);
        for ($i = 0; $i < count($keys) && ! $found; $i ++) {
            $v = $in[$keys[$i]];
            if (($strict === TRUE && $value === $v) || ($strict === FALSE && $value == $v)) {
                $found = TRUE;
            } else 
                if (is_array($v)) {
                    $found = $this->containsIn($value, $strict, $v);
                }
        }
        return $found;
    }

