public static function forget(& $array, $keys)
	{
		$original = & $array;
		$keys = (array) $keys;
		$depth = false;

		if (count($keys) === 0)
		{
			return;
		}

		foreach ($keys as $key)
		{
			if( $depth )
			{
				$array = & $original;
				$depth = false;
			}

			// if the exact key exists in the top-level, remove it
			if( ! static::exists($array, $key))
			{
				// else find key
				for( $i = 0, $parts = explode('.', $key), $count = count($parts); $i < $count; $i++ )
				{
					$key = $parts[$i];
					if( $i + 1 == $count )
					{
						break;
					}

					if( isset($array[$key]) && is_array($array[$key]))
					{
						$array = & $array[$key];
						$depth = true;
					}
					else
					{
						continue 2;
					}
				}
			}

			unset($array[$key]);
		}
	}

