protected function stringArray(Array $data)
    {
        $str = EOL . HT . '[' . EOL;

        foreach( $data as $key => $val )
        {
            $str .= HT . HT . "'" . $key . "' => '" . $val . "'," . EOL;
        }

        $str  = Base::removeSuffix($str, ',' . EOL);
