public function load(array $map = [])
    {
        //每次新加载，清空resolved
        $this->resolved = [];
        foreach ($map as $k => $v) {
            if (is_array($v)) {
                $newMap = [];
                foreach ($v as $k1 => $v1) {
                    $newMap[$k . '.' . $k1] = $v1;
                }
                $this->load($newMap);
            } else {
                $parts = explode('.', $k);
                $max = count($parts) - 1;
                $pos =& $this->map;
                for ($i = 0; $i <= $max; $i++) {
                    $part = $parts[$i];
                    if ($i < $max) {
                        if (!isset($pos[$part])) {
                            $pos[$part] = [];
                        }
                        $pos =& $pos[$part];
                    } else {
                        $pos[$part] = $v;
                    }
                }
            }
        }
    }

