private function convertCompositeToPg($data, TypeInterface $type)
    {
        $mapping = $this->getMapping($type);

        if ($normalizer = $this->getNormalizer($type)) {
            $data = $normalizer->toPg($data, [
                'mapping' => $mapping,
            ]);
        }

        $fragments = [];

        foreach ($mapping as $field => $fieldType) {
            if (!isset($data[$field])) {
                $fragments[$field] = $fieldType instanceof ArrayType ? new Set([], $fieldType) : new Value('null');

                continue;
            }

            $fragments[$field] = $this->toPg($data[$field], $fieldType);
        }

        return new Row($fragments, $type);
    }

