private function buildType($type)
    {
        if ($type instanceof TypeInterface) {
            return $type;
        }

        if (substr($type, -2) === '[]') {
            return new ArrayType($this->buildType(substr($type, 0, -2)));
        }

        return new Type($type);
    }

private function buildMapping($mapping)
    {
        foreach ($mapping as $field => $type) {
            $mapping[$field] = $this->buildType($type);
        }

        return $mapping;
    }

