protected function send()
    {
        if (!$this->initialized) {
            $this->initialized = true;
            $this->sendHeader = $this->headersAccepted();

            if (!$this->sendHeader) {
                return;
            }
        }

        $jsonEncoded = json_encode($this->json);
        $jsonEncoded = str_replace("\n", '', $jsonEncoded);
        $encoded = base64_encode(utf8_encode($jsonEncoded));

        // Note it's 240KB to leave room for an error message
        if (strlen($encoded) > 240*1024) {
            $this->overflowed = true;

            $this->json['rows'][count($this->json['rows']) - 1] = array(
                'Logs truncated, exceeded Chrome header size limit',
                '',
                ''
            );

            $jsonEncoded = json_encode($this->json);
            $jsonEncoded = str_replace("\n", '', $jsonEncoded);
            $encoded = base64_encode(utf8_encode($jsonEncoded));
        }

        $this->sendHeader($encoded);
    }

public static function histogram($values, $edges)
    {
        $bins = [];
        foreach ($edges as $key => $val) {
            if (!isset($edges[$key + 1])) break;
            $bins[] = $val . '-' . ($edges[$key + 1]);
        }

        $histogram = array_fill_keys($bins, []);
        foreach ($values as $value) {
            $i = MathHelper::binary_search($edges, $value);
            if ($i == -1) {
                $message = "Value $value is outside of specified edges array: " . print_r($edges, true) . "\n";
                throw new \Exception($message);
            }
            $key = $bins[$i];
            $histogram[$key][] = $value;
        }
        return $histogram;
    }

