public static function binary_search($list, $x)
    {
        $left = 0;                  # first index of the array to be searched
        $right = count($list) - 1;  # last index of the array to be searched

        if (($x < $list[$left]) || ($x >= $list[$right])) {
            return -1;
        }

        while ($right - $left > 1) {
            $mid = (int)floor(($left + $right) / 2);

            if ($list[$mid] == $x) {
                return $mid;
            } elseif ($list[$mid] > $x) {
                $right = $mid;
            } elseif ($list[$mid] < $x) {
                $left = $mid;
            }
        }
        return $left;
    }

