            ? (array) $headers['Set-Cookie']
            : array();
        $cookies = array();
        foreach ($cookiesRaw as $header) {
            $pairs = \explode(';', $header);
            $pair = \explode('=', $pairs[0]);
            $key = \array_shift($pair);
            $value = \array_shift($pair);
