        $directory = new \DirectoryIterator($this->root . $this->path);
        foreach ($directory as $fileInfo) {
            $fileName = $fileInfo->getFilename();
            if (($fileName === '.') ||
                 ($fileName === '..') ||
                 ($fileName === 'CVS'))
