            $parameter = ':numbered_holder_' . $parameter;
        }
        return parent::bindValue($parameter, $value, $data_type);
    }

protected function buildAccessibleProperties()
    {
        $body = '';

        foreach ($this->accessibleProperties as $accessibleProperty) {
            $body .= sprintf(
                '$object->%s = $data[%s];',
                $accessibleProperty->getName(),
                var_export($accessibleProperty->getName(), true)
            )."\n";
        }

        return $body;
    }

protected function buildPropertyWriters()
    {
        $body = '';

        foreach ($this->propertyWriters as $propertyWriter) {
            $body .= sprintf(
                '$this->%s->__invoke($object, $data[%s]);',
                $propertyWriter->props[0]->name,
                var_export($propertyWriter->getOriginalProperty()->getName(), true)
            )."\n";
        }

        return $body;
    }

public function encrypt($message)
    {
        $authKey    = $this->authen($this->password);
        $cipherText = parent::encrypt($message);

        $mac = \hash_hmac(self::ALGORITHM, $cipherText, $authKey, true);

        return \base64_encode($mac . $cipherText);
    }

public function decrypt($message)
    {
        $authKey = $this->authen($this->password);
        $data    = \base64_decode($message, true);

        if ($data === false)
        {
            throw new Exceptions\Runtime('IV generation failed');
        }

        $hash = \hash(self::ALGORITHM, '', true);

        $hs  = \mb_strlen($hash, '8bit');
        $mac = \mb_substr($data, 0, $hs, '8bit');

        $cipherText = \mb_substr($data, $hs, null, '8bit');

        $calculated = \hash_hmac(
            self::ALGORITHM,
            $cipherText,
            $authKey,
            true
        );

        if (!\hash_equals($mac, $calculated))
        {
            return null;
        }

        return parent::decrypt($cipherText);
    }

