public function editTinyMcePluginLoaderConfig ($arrTinyConfig) {
		$arrTinyConfig["insertdatetime_formats"] = '["' . $this->transformFormat($GLOBALS['TL_CONFIG']['dateFormat']) . '", "' . $this->transformFormat($GLOBALS['TL_CONFIG']['timeFormat']) . '"],';
