public function transactional($func)
    {
        $transaction = new Transaction($this);
        $transaction->beginTransaction();

        try {
            $return = call_user_func($func, $transaction);

            $this->flush();
            $transaction->commit();

            return $return ?: true;
        } catch (\Exception $e) {
            $this->close();
            $transaction->rollback();

            throw $e;
        }
    }

