public static function defaults(bool $includeDeprecated = false): array {
        static $enabled = [];
        if ($includeDeprecated) {
            return static::$_defaults;
        }

        if (!$enabled) {
            foreach (static::$_defaults as $key => $default) {
                !static::isKeyDeprecated($key) && $enabled[$key] = $default;
            }
        }
        return $enabled;
    }

