public function equal($param, $value = null)
    {
        if (func_num_args() == 1) {
            if (!is_array($param)) {
                throw new Exception\InvalidArgumentException(sprintf(
                    "An array is expected when passing one value, received %s",
                    gettype($param)
                ));
            }
            $params = $param;
        } else {
            $params = [$param => $value];
        }

        foreach ($params as $columnName => $value) {
            $this->addCondition('equalTo', [$columnName, $value]);
        }
        return $this;
    }

public function not(array $params)
    {
        foreach ($params as $columnName => $value) {
            $this->addCondition('notEqualTo', [$columnName, $value]);
        }
        return $this;
    }

protected function addCondition($method, array $params)
    {
        $target = $this->getCurrentPredicate();

        # Set default operator if any.
        if ($operator = $this->getDefaultOperator()) {
            $target->$operator;
        }

        call_user_func_array([$target, $method], $params);
    }

protected function expandPlaceholders(&$expression, array &$params)
    {
        if (!$params || false === strpos($expression, '?')) {
            return;
        }

        $convert = false;

        foreach ($params as $param) {
            if (is_array($param)) {
                $convert = true;
                break;
            }
        }

        if (!$convert) {
            return;
        }

        $flatParams = [];
        $parts      = explode('?', $expression);

        foreach ($parts as $i => &$part) {
            if (isset($params[$i])) {
                if (is_array($params[$i])) {
                    $part .= implode(
                        ', ',
                        array_fill(0, count($params[$i]), '?')
                    );
                    $flatParams = array_merge($flatParams, $params[$i]);
                } else {
                    $part .= '?';
                    $flatParams[] = $params[$i];
                }
            }
        }

        $expression = implode('', $parts);
        $params     = $flatParams;
    }

