        $dir = $this->getCachePath();
        foreach ($objects as $object) {
            if ($object != "." && $object != "..") {
                if (is_dir($dir.$object)) {
                    self::rrmdir($dir.$object);
                } elseif ($object !== 'cache_config') {
                    unlink($dir.$object);
                }
            }
