public static function chunkSplitArr($string, $chunkLen, $padding = '0')
    {
        $count = strlen($string);
        $parts = [];

        for ($i = 0; $i < $count; $i = $i + $chunkLen) {
            if (strlen($string) < $chunkLen) {
                $string .= $padding;
            }
            $parts[] = substr($string, 0, $chunkLen);
            $string = substr($string, $chunkLen);
        }

        return $parts;
    }

