public function save() {
		$ownerTransaction = FALSE;
		try {
			if ($this->database->getConnection()->getPdo()->inTransaction() === FALSE) {
				$this->database->beginTransaction();
				$ownerTransaction = TRUE;
			}
			if (is_array($this->rows)) {
				foreach ($this->rows as $key => $row) {
					if ($row->toRow()) {
						$this->update($row);
