public function handleFatal()
    {
        $error = error_get_last();
        if ($error) {
            switch ($error['type']) {
                case E_ERROR:
                case E_PARSE:
                case E_CORE_ERROR:
                case E_COMPILE_ERROR:
                case E_USER_ERROR:
                    $this->logger->log(
                        $this->map[$error['type']],
                        'Fatal error (' . self::$strings[$error['type']] . '): ' . $error['message'],
                        array(
                            'file' => $error['file'],
                            'line' => $error['line'],
                            'code' => $error['type']
                        )
                    );
            }
        }
    }

public static function detect($callable, $mask = -1)
    {
        $error = null;
        set_error_handler(function ($type, $message, $file, $line) use ($error) {
            $error = new ErrorException($message, 0, $type, $file, $line);
        }, $mask);
        $callable();
        restore_error_handler();
        return $error;
    }

