public final function useRoute(string $fileName): ApplicationInterface
    {
        try {
            if (!$this->router) {
                $this->router = $this->getRouter();
            }
            $this->router->import($fileName);
        } catch (InvalidArgumentException $e) {
            throw new InvalidArgumentException(
                "Can't use routes: ". $e->getMessage()
            );
        }
        return $this;
    }

public final function useLogger(string $includePath): ApplicationInterface
    {
        if (!is_dir($includePath)) {
            throw new InvalidArgumentException(
                "Can't use logger: expect \""
                . $includePath . "\" to be a directory"
            );
        }
        $this->logDirectory = $includePath;
        return $this;
    }

public final function run(): ResponseInterface
    {
        try {
            $this->prepare();
            try {
                $body = "";
                $container = $this->getContainer();
                $controller = $this->getController($container);
                $body = $controller->execute($container);
                unset($container);
                $response = $controller->getResponse();
                unset($controller);
                return $this->send($response, $body);
            } catch (RuntimeException $e) {
                trigger_error("Run warning: " . $e->getMessage(), E_USER_WARNING);
                unset($container);
                return $this->send($controller->getResponse(), $body);
            } catch (RouterException $e) {
                trigger_error("Run notice: " . $e->getMessage(), E_USER_NOTICE);
                return $this->send($this->getResponse()->withStatus(404), $body);
            } catch (DispatcherException $e) {
                trigger_error("Run error: " . $e->getMessage(), E_USER_ERROR);
                return $this->send($this->getResponse()->withStatus(500), $body);
            }
        } catch (RuntimeException $e) {
            throw new RuntimeException("Can't run application: " . $e->getMessage());
        }
    }

