        $url = Yii::$app->request->getAbsoluteUrl();
        $parse = parse_url($url);
        if ( ! empty($parse)) {
            $path = explode('/', trim($parse['path']), $this->uriPosition + 1);
            is_string($path) and $path = [$path];
            if (isset($parse[$this->uriPosition - 1])) {
