                    $filename = $path.'/'.$views[$i].'.php';
                    if (!file_exists($filename))
                        file_put_contents(
                            $filename,
                            preg_replace('/\{0\}/', $key, $this->getTemplate($template))
                        );
                } else {
                    // Directory check
                    $path .= '/'.$views[$i];
                    if (!is_dir($path))
                        mkdir($path);
                }
            }
            // Print end
            $this->_print('View created!');
            $this->_lineBreak();
        } catch (Exception $e) {
            file_put_contents(
                $this->rootPath.'/error_log',
                $e->getMessage()
            );
            throw new NoticeException('Command "'.$this->key.'": Fatal error ocurred.');
        }
    }

