            echo '<pre>';
            if (array_key_exists($type, $functions)) {

                if ($functions[$type] === 'echo') {

                    echo $data;
                } else if ($functions[$type] === 'json_encode') {

                    $json = json_decode($data);
                    echo json_encode($json, JSON_PRETTY_PRINT);
