        if (!self::exists($path)) {
            return [];
        }
        $files = array_filter(scandir($path), function ($item) use ($path, $filter) {
            if ($item == '.' || $item == '..' || is_dir($path . '/' . $item)) {
                return false;
            }
            if (!empty($filter) && (pathinfo($item)['extension'] != trim($filter, '.'))) {
                return false;
            }
            return true;
        });

        $files = array_map(function ($item) use ($path) {
            return $path . '/' . $item;
        }, $files);

        return $files;
    }

