public function add_data( $data ) : View_Factory {
		if ( \is_array( $data ) ) {
			foreach ( $data as $key => $value ) {
				$data_to_add = $value;
				if ( $value instanceof Presentable_Model ) {
					$data_to_add = $value->present();
				} elseif ( \is_object( $value ) ) {
