public function url($default, $query = null, $fragment = null) {
		$url_query = (stristr($default, '?'))?'&':'?';

		if (is_array($query)) {
			$itter = 0;
			foreach ($query as $key => $value) { if ($itter == array_search( $key, $query )) {
				$itter++;
				$url_query .= $key.'='.$value;
			} else {
				$url_query .= '&'.$key.'='.$value;
